import { cn } from '@/utils/cn';
import { cva, VariantProps } from 'class-variance-authority';
import {
  Component,
  createMemo,
  For,
  Match,
  mergeProps,
  ParentComponent,
  Show,
  Switch,
} from 'solid-js';
import type { AvatarGroup, AvatarProps } from './avatar.types';

const variants = cva('', {
  variants: {
    mask: {
      heart: 'mask mask-heart',
      hexagon: 'mask mask-hexagon',
      squircle: 'mask mask-squircle',
      square: 'rounded-lg',
      circle: 'rounded-full',
    },
    status: {
      online: 'avatar-online',
      offline: 'avatar-offline',
    },
  },
});

export type AvatarVariantsProps = VariantProps<typeof variants>;

export function Avatar(p: AvatarProps): ReturnType<Component<AvatarProps>> {
  p = mergeProps(
    {
      mask: 'circle' as const,
      effect: true,
    },
    p,
  );

  return (
    <div
      class={cn(
        'avatar',
        p.placeholder && 'avatar-placeholder',
        variants({ status: p.status }),
        p.effect && 'avatar-effect',
        p.class?.root,
      )}
    >
      <Switch>
        <Match when={p.placeholder}>{p.placeholder as Element}</Match>
        <Match when={p.image}>
          <div
            class={cn(variants({ mask: p.mask }), p.class?.avatar)}
            style={{ width: typeof p.width === 'string' ? p.width : `${p.width}px` }}
          >
            {p.image && <img src={p.image} />}
          </div>
        </Match>
      </Switch>
    </div>
  );
}

Avatar.Group = (props: AvatarGroup): ReturnType<ParentComponent> => {
  const renderWidth = createMemo(() => {
    return typeof props.width === 'string' ? props.width : `${props.width}px`;
  });
  return (
    <div class={cn('avatar-group -space-x-6', props.class?.group)}>
      <For each={props.avatars}>{avatar => <Avatar {...avatar} width={renderWidth()} />}</For>
      <Show when={props.counter}>
        <div class={cn('avatar avatar-placeholder', props.class?.placeholder)}>
          <div
            class={cn('bg-neutral text-neutral-content', props.class?.counter)}
            style={{
              width: renderWidth(),
            }}
          >
            +{props.counter}
          </div>
        </div>
      </Show>
    </div>
  );
};
